# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char BUILD_CHARS[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CHARS[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2]; // true = impassable
int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;

// Wall plan: L-shaped wall for corner enclosure
// We'll use top-left corner by default
// Enclosure: rows 1..ER, cols 1..EC
// Walls: row ER+1 cols 1..EC, and col EC+1 rows 1..ER
// Plus corner at (ER+1, EC+1) to prevent diagonal leak
int enclosure_rows, enclosure_cols;
int wall_row, wall_col; // row and col where walls are placed
std::vector<Point> wall_plan;
std::vector<bool> wall_built;

// BFS helpers
int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

bool valid(Point p) {
    return p.r >= 1 && p.r <= GRID_SIZE && p.c >= 1 && p.c <= GRID_SIZE;
}

bool passable(Point p) {
    return valid(p) && !grid[p.r][p.c];
}

int manhattan(Point a, Point b) {
    return std::abs(a.r - b.r) + std::abs(a.c - b.c);
}

void bfs_from(Point start) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    if (!valid(start)) return;
    std::queue<Point> q;
    bfs_dist[start.r][start.c] = 0;
    bfs_parent[start.r][start.c] = {-1, -1};
    q.push(start);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point nxt = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (passable(nxt) && bfs_dist[nxt.r][nxt.c] == -1) {
                bfs_dist[nxt.r][nxt.c] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nxt.r][nxt.c] = cur;
                q.push(nxt);
            }
        }
    }
}

// Get first step from start toward target using BFS
char get_move_toward(Point start, Point target) {
    if (start == target) return '.';
    bfs_from(start);
    if (bfs_dist[target.r][target.c] == -1) return '.';

    Point cur = target;
    while (!(bfs_parent[cur.r][cur.c] == start)) {
        cur = bfs_parent[cur.r][cur.c];
        if (cur.r == -1) return '.';
    }
    for (int d = 0; d < 4; d++) {
        if (start.r + DIRS[d].r == cur.r && start.c + DIRS[d].c == cur.c) {
            return MOVE_CHARS[d];
        }
    }
    return '.';
}

// Count pets inside the enclosure area
int count_pets_inside() {
    int count = 0;
    for (auto& pet : pets) {
        if (pet.pos.r >= 1 && pet.pos.r <= enclosure_rows &&
            pet.pos.c >= 1 && pet.pos.c <= enclosure_cols) {
            count++;
        }
    }
    return count;
}

// Check if a point is inside the enclosure
bool is_inside_enclosure(Point p) {
    return p.r >= 1 && p.r <= enclosure_rows && p.c >= 1 && p.c <= enclosure_cols;
}

// Determine the best corner to use based on initial pet positions
// Returns: 0=top-left, 1=top-right, 2=bottom-left, 3=bottom-right
int choose_best_corner(int er, int ec) {
    int counts[4] = {0, 0, 0, 0};
    for (auto& pet : pets) {
        // top-left: rows 1..er, cols 1..ec
        if (pet.pos.r <= er && pet.pos.c <= ec) counts[0]++;
        // top-right: rows 1..er, cols (GRID_SIZE-ec+1)..GRID_SIZE
        if (pet.pos.r <= er && pet.pos.c > GRID_SIZE - ec) counts[1]++;
        // bottom-left: rows (GRID_SIZE-er+1)..GRID_SIZE, cols 1..ec
        if (pet.pos.r > GRID_SIZE - er && pet.pos.c <= ec) counts[2]++;
        // bottom-right
        if (pet.pos.r > GRID_SIZE - er && pet.pos.c > GRID_SIZE - ec) counts[3]++;
    }
    int best = 0;
    for (int i = 1; i < 4; i++) {
        if (counts[i] < counts[best]) best = i;
    }
    return best;
}

// Transform a point based on corner choice
// Internal logic uses top-left (rows 1..ER, cols 1..EC)
// We transform to/from actual grid coordinates
int corner_choice;

Point to_actual(Point internal) {
    int r = internal.r, c = internal.c;
    switch (corner_choice) {
        case 0: return {r, c}; // top-left, no transform
        case 1: return {r, GRID_SIZE + 1 - c}; // top-right, mirror cols
        case 2: return {GRID_SIZE + 1 - r, c}; // bottom-left, mirror rows
        case 3: return {GRID_SIZE + 1 - r, GRID_SIZE + 1 - c}; // bottom-right, mirror both
    }
    return {r, c};
}

Point to_internal(Point actual) {
    int r = actual.r, c = actual.c;
    switch (corner_choice) {
        case 0: return {r, c};
        case 1: return {r, GRID_SIZE + 1 - c};
        case 2: return {GRID_SIZE + 1 - r, c};
        case 3: return {GRID_SIZE + 1 - r, GRID_SIZE + 1 - c};
    }
    return {r, c};
}

// Build the wall plan in actual coordinates
void build_wall_plan() {
    wall_plan.clear();
    wall_row = enclosure_rows + 1;
    wall_col = enclosure_cols + 1;

    // Horizontal wall: internal row wall_row, cols 1..enclosure_cols
    for (int c = 1; c <= enclosure_cols; c++) {
        wall_plan.push_back(to_actual({wall_row, c}));
    }
    // Vertical wall: internal col wall_col, rows 1..enclosure_rows
    for (int r = 1; r <= enclosure_rows; r++) {
        wall_plan.push_back(to_actual({r, wall_col}));
    }
    // Corner piece
    wall_plan.push_back(to_actual({wall_row, wall_col}));

    wall_built.assign(wall_plan.size(), false);
}

bool can_build_at(Point wall_pos, int human_idx) {
    if (!valid(wall_pos)) return false;
    if (grid[wall_pos.r][wall_pos.c]) return false; // already impassable

    // Can't build on a square with a pet
    for (auto& pet : pets) {
        if (pet.pos == wall_pos) return false;
        // Can't build adjacent to a pet
        if (manhattan(wall_pos, pet.pos) == 1) return false;
    }
    // Can't build on a square with a human
    for (int i = 0; i < M; i++) {
        if (humans[i].pos == wall_pos) return false;
    }
    return true;
}

// Find the best wall to build and the position to stand at
struct BuildAction {
    int wall_idx;
    Point stand_pos;
    int dist;
};

BuildAction find_best_build(int human_idx) {
    BuildAction best = {-1, {-1, -1}, INF};
    Point hpos = humans[human_idx].pos;

    bfs_from(hpos);

    for (int wi = 0; wi < (int)wall_plan.size(); wi++) {
        if (wall_built[wi]) continue;
        Point wp = wall_plan[wi];
        if (grid[wp.r][wp.c]) { wall_built[wi] = true; continue; }

        // Find adjacent standing position
        for (int d = 0; d < 4; d++) {
            Point sp = {wp.r + DIRS[d].r, wp.c + DIRS[d].c};
            if (!passable(sp)) continue;
            if (bfs_dist[sp.r][sp.c] == -1) continue;

            int dist = bfs_dist[sp.r][sp.c];
            if (dist < best.dist) {
                best = {wi, sp, dist};
            }
        }
    }
    return best;
}

int main() {
