#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = 1e9;

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char BUILD_CHARS[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CHARS[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
    std::vector<int> assigned_walls; // indices into wall_plan
    int current_target; // index in assigned_walls, or -1
};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];
int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;

int enclosure_rows, enclosure_cols;
std::vector<Point> wall_plan;
std::vector<bool> wall_built;
int corner_choice;

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

bool valid(Point p) {
    return p.r >= 1 && p.r <= GRID_SIZE && p.c >= 1 && p.c <= GRID_SIZE;
}

bool passable(Point p) {
    return valid(p) && !grid[p.r][p.c];
}

int manhattan(Point a, Point b) {
    return std::abs(a.r - b.r) + std::abs(a.c - b.c);
}

void bfs_from(Point start) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    if (!valid(start) || !passable(start)) return;
    std::queue<Point> q;
    bfs_dist[start.r][start.c] = 0;
    bfs_parent[start.r][start.c] = {-1, -1};
    q.push(start);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point nxt = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (passable(nxt) && bfs_dist[nxt.r][nxt.c] == -1) {
                bfs_dist[nxt.r][nxt.c] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nxt.r][nxt.c] = cur;
                q.push(nxt);
            }
        }
    }
}

char get_move_toward(Point start, Point target) {
    if (start == target) return '.';
    bfs_from(start);
    if (bfs_dist[target.r][target.c] == -1) return '.';
    Point cur = target;
    while (!(bfs_parent[cur.r][cur.c] == start)) {
        cur = bfs_parent[cur.r][cur.c];
        if (cur.r == -1) return '.';
    }
    for (int d = 0; d < 4; d++) {
        if (start.r + DIRS[d].r == cur.r && start.c + DIRS[d].c == cur.c) {
            return MOVE_CHARS[d];
        }
    }
    return '.';
}

Point to_actual(Point internal) {
    int r = internal.r, c = internal.c;
    switch (corner_choice) {
        case 0: return {r, c};
        case 1: return {r, GRID_SIZE + 1 - c};
        case 2: return {GRID_SIZE + 1 - r, c};
        case 3: return {GRID_SIZE + 1 - r, GRID_SIZE + 1 - c};
    }
    return {r, c};
}

Point to_internal(Point actual) {
    int r = actual.r, c = actual.c;
    switch (corner_choice) {
        case 0: return {r, c};
        case 1: return {r, GRID_SIZE + 1 - c};
        case 2: return {GRID_SIZE + 1 - r, c};
        case 3: return {GRID_SIZE + 1 - r, GRID_SIZE + 1 - c};
    }
    return {r, c};
}

int count_pets_in_region(int er, int ec, int corner) {
    int count = 0;
    for (auto& pet : pets) {
        Point ip;
        switch (corner) {
            case 0: ip = {pet.pos.r, pet.pos.c}; break;
            case 1: ip = {pet.pos.r, GRID_SIZE + 1 - pet.pos.c}; break;
            case 2: ip = {GRID_SIZE + 1 - pet.pos.r, pet.pos.c}; break;
            case 3: ip = {GRID_SIZE + 1 - pet.pos.r, GRID_SIZE + 1 - pet.pos.c}; break;
        }
        if (ip.r >= 1 && ip.r <= er && ip.c >= 1 && ip.c <= ec) count++;
    }
    return count;
}

void build_wall_plan() {
    wall_plan.clear();
    int wr = enclosure_rows + 1;
    int wc = enclosure_cols + 1;

    // Horizontal wall: row wr, cols 1..enclosure_cols
    for (int c = 1; c <= enclosure_cols; c++) {
        wall_plan.push_back(to_actual({wr, c}));
    }
    // Vertical wall: col wc, rows 1..enclosure_rows
    for (int r = 1; r <= enclosure_rows; r++) {
        wall_plan.push_back(to_actual({r, wc}));
    }
    // Corner piece
    wall_plan.push_back(to_actual({wr, wc}));

    wall_built.assign(wall_plan.size(), false);
}

bool can_build_at(Point wall_pos) {
    if (!valid(wall_pos)) return false;
    if (grid[wall_pos.r][wall_pos.c]) return true; // already built, that's fine
    for (auto& pet : pets) {
        if (pet.pos == wall_pos) return false;
        if (manhattan(wall_pos, pet.pos) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].pos == wall_pos) return false;
    }
    return true;
}

// Assign walls to humans greedily based on proximity
void assign_walls_to_humans() {
    for (int i = 0; i < M; i++) {
        humans[i].assigned_walls.clear();
        humans[i].current_target = -1;
    }

    std::vector<bool> assigned(wall_plan.size(), false);

    // Assign walls round-robin, each time picking the closest unassigned wall to the human
    int walls_per_human = (wall_plan.size() + M - 1) / M;

    for (int round = 0; round < walls_per_human; round++) {
        for (int i = 0; i < M; i++) {
            int best_wi = -1;
            int best_dist = INF;
            for (int wi = 0; wi < (int)wall_plan.size(); wi++) {
                if (assigned[wi]) continue;
                int d = manhattan(humans[i].pos, wall_plan[wi]);
                if (d < best_dist) {
                    best_dist = d;
                    best_wi = wi;
                }
            }
            if (best_wi != -1) {
                humans[i].assigned_walls.push_back(best_wi);
                assigned[best_wi] = true;
            }
        }
    }
}

Point find_stand_pos_for_wall(Point wp) {
    // Find the best adjacent passable position to stand to build this wall
    Point best = {-1, -1};
    int best_dist = INF;
    for (int d = 0; d < 4; d++) {
        Point sp = {wp.r + DIRS[d].r, wp.c + DIRS[d].c};
        if (passable(sp)) {
            // Prefer positions inside/near the enclosure
            if (best.r == -1) best = sp;
            else {
                // Just pick first valid one
                best = sp;
                break;
            }
        }
    }
    if (best.r == -1) {
        // Try any valid adjacent
        for (int d = 0; d < 4; d++) {
            Point sp = {wp.r + DIRS[d].r, wp.c + DIRS[d].c};
            if (valid(sp) && !grid[sp.r][sp.c]) {
                best = sp;
                break;
            }
        }
    }
    return best;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].pos.r >> humans[i].pos.c;
    }

    memset(grid, false, sizeof(grid));

    // Try different enclosure sizes and pick best (fewest pets, good area)
    enclosure_rows = 14;
    enclosure_cols = 14;

    int best_score = -INF;
    int best_er = 14, best_ec = 14, best_corner = 0;

    for (int er = 10; er <= 18; er += 2) {
        for (int ec = 10; ec <= 18; ec += 2) {
            for (int corner = 0; corner < 4; corner++) {
                int pets_inside = count_pets_in_region(er, ec, corner);
                int area = er * ec;
                int walls_needed = er + ec + 1;
                // Score: large area is good, few pets inside is good
                // area/900 * 2^(-pets_inside) * 10^8 roughly
                // Simplified: area * 2^(-pets_inside) - penalty for walls
                double score = (double)area * std::pow(2.0, -pets_inside) - walls_needed * 0.5;
                if (score > best_score) {
                    best_score = score;
                    best_er = er;
                    best_ec = ec;
                    best_corner = corner;
                }
            }
        }
    }

    enclosure_rows = best_er;
    enclosure_cols = best_ec;
    corner_choice = best_corner;

    build_wall_plan();
    assign_walls_to_humans();

    Point gather_actual = to_actual({enclosure_rows / 2, enclosure_cols / 2});

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M, '.');

        // Update wall_built status
        for (int wi = 0; wi < (int)wall_plan.size(); wi++) {
            if (!wall_built[wi] && grid[wall_plan[wi].r][wall_plan[wi].c]) {
                wall_built[wi] = true;
            }
        }

        bool all_walls_done = true;
        for (int wi = 0; wi < (int)wall_plan.size(); wi++) {
            if (!wall_built[wi]) { all_walls_done = false; break; }
        }

        std::vector<Point> tentative_builds;

        for (int i = 0; i < M; i++) {
            Point hpos = humans[i].pos;

            if (all_walls_done) {
                // Move inside enclosure
                if (hpos == gather_actual) {
                    actions[i] = '.';
                } else {
                    char mv = get_move_toward(hpos, gather_actual);
                    actions[i] = mv;
                }
                continue;
            }

            // Find next unbuilt wall from our assignment
            int target_wi = -1;
            for (int wi : humans[i].assigned_walls) {
                if (!wall_built[wi] && !grid[wall_plan[wi].r][wall_plan[wi].c]) {
                    target_wi = wi;
                    break;
                }
            }

            // If all our assigned walls are done, help others
            if (target_wi == -1) {
                for (int wi = 0; wi < (int)wall_plan.size(); wi++) {
                    if (!wall_built[wi] && !grid[wall_plan[wi].r][wall_plan[wi].c]) {
                        target_wi = wi;
                        break;
                    }
                }
            }

            if (target_wi == -1) {
                // All walls done, move to gather
                if (hpos != gather_actual) {
                    actions[i] = get_move_toward(hpos, gather_actual);
                }
                continue;
            }

            Point wp = wall_plan[target_wi];

            // Find standing position adjacent to this wall
            Point sp = {-1, -1};
            int best_sp_dist = INF;
            bfs_from(hpos);

            for (int d = 0; d < 4; d++) {
                Point candidate = {wp.r + DIRS[d].r, wp.c + DIRS[d].c};
                if (!valid(candidate) || grid[candidate.r][candidate.c]) continue;
                if (bfs_dist[candidate.r][candidate.c] == -1) continue;

                bool is_tentative = false;
                for (auto& tb : tentative_builds) {
                    if (tb == candidate) { is_tentative = true; break; }
                }
                if (is_tentative) continue;

                int dist = bfs_dist[candidate.r][candidate.c];
                if (dist < best_sp_dist) {
                    best_sp_dist = dist;
                    sp = candidate;
                }
            }

            if (sp.r == -1) {
                // Can't reach any standing position for this wall
                actions[i] = '.';
                continue;
            }

            if (hpos == sp) {
                // Try to build
                if (can_build_at(wp)) {
                    bool already_planned = false;
                    for (auto& tb : tentative_builds) {
                        if (tb == wp) { already_planned = true; break; }
                    }
                    if (!already_planned) {
                        for (int d = 0; d < 4; d++) {
                            if (hpos.r + DIRS[d].r == wp.r && hpos.c + DIRS[d].c == wp.c) {
                                actions[i] = BUILD_CHARS[d];
                                tentative_builds.push_back(wp);
                                break;
                            }
                        }
                    }
                }
            } else {
                // Move toward standing position
                // Use parent trace from earlier bfs_from(hpos)
                Point cur = sp;
                while (!(bfs_parent[cur.r][cur.c] == hpos)) {
                    cur = bfs_parent[cur.r][cur.c];
                    if (cur.r == -1) { actions[i] = '.'; goto next_human; }
                }
                for (int d = 0; d < 4; d++) {
                    if (hpos.r + DIRS[d].r == cur.r && hpos.c + DIRS[d].c == cur.c) {
                        // Check not moving into a tentative build
                        bool conflict = false;
                        for (auto& tb : tentative_builds) {
                            if (cur == tb) { conflict = true; break; }
                        }
                        if (!conflict) {
                            actions[i] = MOVE_CHARS[d];
                        }
                        break;
                    }
                }
            }
            next_human:;
        }

        std::cout << actions << std::endl;

        // Apply builds
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CHARS[d]) {
                        Point wp = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                        if (valid(wp)) grid[wp.r][wp.c] = true;
                        break;
                    }
                }
            }
        }

        // Apply moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CHARS[d]) {
                        Point np = {humans[i].pos.r + DIRS[d].r, humans[i].pos.c + DIRS[d].c};
                        if (passable(np)) humans[i].pos = np;
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char c : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (c == MOVE_CHARS[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
# EVOLVE-BLOCK-END

